+  it("easeOutExpo returns 1 at t=1", () => {
+    expect(easings.easeOutExpo(1)).toBe(1);
+  });
+
+  it("easeOutExpo is monotonically increasing", () => {
+    let prev = easings.easeOutExpo(0);
+    for (let t = 0.1; t <= 1; t += 0.1) {
+      const current = easings.easeOutExpo(t);
